queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?trail_id ?difficulty WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTrails ?child ; p:hasNational_Parks ?parent . } GROUP BY ?child }
  ?child p:trail_id ?trail_id .
  ?child p:difficulty ?difficulty .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :National_Parks } }
  FILTER(?nf = ?total)
}

